// Processar arquivos anexados e extrair dados
const items = $input.all();
let prompt = '';
let attachedData = '';
let hasFiles = false;

for (const item of items) {
  // Extrair o prompt do body
  if (item.json.body) {
    prompt = item.json.body.prompt || item.json.body.message || '';
  }
  if (!prompt && item.json.prompt) {
    prompt = item.json.prompt;
  }

  // Processar arquivos binários anexados
  if (item.binary) {
    for (const [key, binaryData] of Object.entries(item.binary)) {
      hasFiles = true;
      const fileName = binaryData.fileName || 'arquivo';
      const mimeType = binaryData.mimeType || '';

      try {
        if (mimeType === 'text/csv' || fileName.endsWith('.csv')) {
          const content = Buffer.from(binaryData.data, 'base64').toString('utf-8');
          const lines = content.split('\n').slice(0, 100);
          attachedData += `\n\n=== DADOS DE ${fileName} (CSV) ===\n${lines.join('\n')}`;
          if (content.split('\n').length > 100) {
            attachedData += `\n... (${content.split('\n').length - 100} linhas adicionais omitidas)`;
          }

        } else if (mimeType === 'text/plain' || fileName.endsWith('.txt')) {
          const content = Buffer.from(binaryData.data, 'base64').toString('utf-8');
          attachedData += `\n\n=== DADOS DE ${fileName} (TEXTO) ===\n${content.substring(0, 5000)}`;

        } else if (mimeType.includes('json') || fileName.endsWith('.json')) {
          const content = Buffer.from(binaryData.data, 'base64').toString('utf-8');
          attachedData += `\n\n=== DADOS DE ${fileName} (JSON) ===\n${content.substring(0, 5000)}`;

        } else if (mimeType.includes('spreadsheet') || mimeType.includes('excel')
                   || fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
          attachedData += `\n\n=== ARQUIVO EXCEL: ${fileName} ===\n[Arquivo Excel detectado - dados serão processados pelo microserviço]`;

        } else if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
          attachedData += `\n\n=== ARQUIVO PDF: ${fileName} ===\n[PDF detectado - texto será extraído pelo microserviço]`;

        } else {
          attachedData += `\n\n=== ARQUIVO: ${fileName} (${mimeType}) ===\n[Tipo de arquivo não processado diretamente]`;
        }
      } catch (e) {
        attachedData += `\n\n=== ERRO ao processar ${fileName}: ${e.message} ===`;
      }
    }
  }
}

if (!prompt) {
  throw new Error('Nenhum prompt encontrado. Envie o campo "prompt" no body da requisição.');
}

return [{
  json: {
    prompt: prompt,
    attachedData: attachedData || 'Nenhum dado anexado pelo usuário.',
    hasFiles: hasFiles
  }
}];

const agentOutput = $input.first().json.output || $input.first().json.text || '';
if (!agentOutput || agentOutput.length < 10) {
  throw new Error('Saida do agente vazia. Tamanho: ' + agentOutput.length);
}
let reasoning = '';
function extractReasoning(text, splitPos) {
  if (splitPos <= 0) return '';
  const before = text.substring(0, splitPos).trim();
  const title = '## Raciocinio e pesquisas';
  const titleAlt = '## Racioc\u00ednio e pesquisas';
  let r = before;
  if (r.includes(title)) r = r.replace(title, '');
  if (r.includes(titleAlt)) r = r.replace(titleAlt, '');
  return r.replace(/^\s+/, '').trim();
}
function tryParse(str) {
  if (!str || str.length < 5) return null;
  try { return JSON.parse(str); } catch (e) { return null; }
}
function sanitize(s) {
  let t = s;
  t = t.replace(/,([\s\r\n]*[}\]])/g, '$1');
  return t;
}
function repairTruncated(str) {
  if (!str || str.length < 10) return null;
  let s = str.trim();
  s = s.replace(/,?\s*"[^"]*$/g, '');
  s = s.replace(/,?\s*"[^"]*"\s*:\s*$/g, '');
  s = s.replace(/,\s*$/g, '');
  const stack = [];
  let inStr = false;
  let esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { esc = false; continue; }
    if (c === '\\') { esc = true; continue; }
    if (c === '"') { inStr = !inStr; continue; }
    if (inStr) continue;
    if (c === '{') stack.push('}');
    else if (c === '[') stack.push(']');
    else if (c === '}' || c === ']') stack.pop();
  }
  while (stack.length > 0) s += stack.pop();
  return tryParse(s);
}
function extractByBraces(text) {
  let startIdx = -1;
  const ptIdx = text.indexOf('"presentation_title"');
  const slIdx = text.indexOf('"slides"');
  const keyIdx = ptIdx >= 0 ? (slIdx >= 0 ? Math.min(ptIdx, slIdx) : ptIdx) : slIdx;
  if (keyIdx >= 0) {
    for (let i = keyIdx; i >= 0; i--) {
      if (text[i] === '{') { startIdx = i; break; }
    }
  }
  if (startIdx === -1) {
    for (let i = 0; i < text.length; i++) {
      if (text[i] === '{') { startIdx = i; break; }
    }
  }
  if (startIdx === -1) return '';
  let depth = 0;
  let endIdx = text.length;
  for (let i = startIdx; i < text.length; i++) {
    if (text[i] === '{' || text[i] === '[') depth++;
    else if (text[i] === '}' || text[i] === ']') {
      depth--;
      if (depth === 0) { endIdx = i + 1; break; }
    }
  }
  return text.substring(startIdx, endIdx);
}
let endReasoning = agentOutput.length;
const i1 = agentOutput.indexOf('```');
if (i1 >= 0 && i1 < endReasoning) endReasoning = i1;
const i2 = agentOutput.indexOf(']son');
if (i2 >= 0 && i2 < endReasoning) endReasoning = i2;
const i3 = agentOutput.indexOf('{"presentation_title"');
if (i3 >= 0 && i3 < endReasoning) endReasoning = i3;
const i4 = agentOutput.indexOf('{"slides"');
if (i4 >= 0 && i4 < endReasoning) endReasoning = i4;
reasoning = extractReasoning(agentOutput, endReasoning);
let normalized = agentOutput.replace(/\"]son/g, ' ').replace(/\"]json/g, ' ').replace(/"json\s*/g, ' ').replace(/']son/g, ' ');
let rawJson = '';
let parsed = null;
const codeBlockRe = /```(?:json)?[\s\n]*([\s\S]+?)[\s\n]*```/;
const cbMatch = normalized.match(codeBlockRe);
if (cbMatch && cbMatch[1] && cbMatch[1].trim().length > 5) {
  rawJson = cbMatch[1].trim();
  parsed = tryParse(sanitize(rawJson));
  if (!parsed) {
    let fixed = rawJson.replace(/'([^']*)'\s*:/g, '"$1":');
    fixed = fixed.replace(/:\s*'([^']*)'/g, ': "$1"');
    parsed = tryParse(sanitize(fixed));
  }
  if (!parsed) {
    const allSingle = rawJson.replace(/'/g, '"');
    parsed = tryParse(sanitize(allSingle));
  }
}
if (!parsed) {
  rawJson = extractByBraces(normalized);
  if (rawJson) {
    parsed = tryParse(sanitize(rawJson));
    if (!parsed) {
      let fixed = rawJson.replace(/'([^']*)'\s*:/g, '"$1":');
      fixed = fixed.replace(/:\s*'([^']*)'/g, ': "$1"');
      parsed = tryParse(sanitize(fixed));
    }
    if (!parsed) {
      const allSingle = rawJson.replace(/'/g, '"');
      parsed = tryParse(sanitize(allSingle));
    }
  }
}
if (!parsed) {
  parsed = tryParse(sanitize(normalized));
}
if (!parsed && rawJson && rawJson.length > 20) {
  parsed = repairTruncated(sanitize(rawJson));
}
if (!parsed) {
  const last200 = rawJson.length > 200 ? rawJson.substring(rawJson.length - 200) : rawJson;
  const dbg = 'agentOutput.length=' + agentOutput.length + ' rawJson.length=' + rawJson.length + ' primeiros 400: ' + normalized.substring(0, 400) + ' | ultimos 200 rawJson: ' + last200;
  throw new Error('Nenhum JSON valido encontrado. ' + dbg);
}
const slidesJson = parsed;
if (!slidesJson.slides || !Array.isArray(slidesJson.slides)) {
  throw new Error('JSON invalido: campo slides nao encontrado ou nao e array');
}
if (slidesJson.slides.length === 0) {
  throw new Error('JSON invalido: array de slides vazio');
}
for (let i = 0; i < slidesJson.slides.length; i++) {
  if (!slidesJson.slides[i].layout) {
    throw new Error('Slide ' + (i+1) + ' sem campo layout');
  }
}
return [{ json: { ...slidesJson, reasoning: reasoning || '' } }];

let reasoning = '';
let presentation_title = 'apresentacao';
try {
  const slidesData = $('Extrair JSON dos Slides').first();
  reasoning = slidesData.json.reasoning || '';
  presentation_title = slidesData.json.presentation_title || 'apresentacao';
} catch (e) {}

const item = $input.first();
const data = item.json || {};

const slides_url = data.slides_url || null;
const sheets_url = data.sheets_url || null;

if (!slides_url) {
  return [{ json: {
    slides_url: null,
    sheets_url: null,
    presentation_title,
    reasoning,
    error: data.detail || data.error || 'Google Slides nao gerado. Verifique as credenciais e o servico.'
  }}];
}

return [{ json: {
  slides_url,
  sheets_url,
  presentation_title: data.presentation_title || presentation_title,
  reasoning
}}];
